package com.google.gson.internal.bind;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.Test;

class TypeAdaptersTest {

  @Test
  void newFactory_create_returnsAdapterForMatchingType() {
    // Arrange
    Class<String> type = String.class;
    @SuppressWarnings("unchecked")
    TypeAdapter<String> typeAdapter = mock(TypeAdapter.class);
    TypeAdapterFactory factory = TypeAdapters.newFactory(type, typeAdapter);
    Gson gson = mock(Gson.class);
    TypeToken<String> matchingTypeToken = TypeToken.get(String.class);

    // Act
    TypeAdapter<String> adapter = factory.create(gson, matchingTypeToken);

    // Assert
    assertNotNull(adapter);
    assertSame(typeAdapter, adapter);
  }

  @Test
  void newFactory_create_returnsNullForNonMatchingType() {
    // Arrange
    Class<String> type = String.class;
    @SuppressWarnings("unchecked")
    TypeAdapter<String> typeAdapter = mock(TypeAdapter.class);
    TypeAdapterFactory factory = TypeAdapters.newFactory(type, typeAdapter);
    Gson gson = mock(Gson.class);
    TypeToken<Integer> nonMatchingTypeToken = TypeToken.get(Integer.class);

    // Act
    TypeAdapter<?> adapter = factory.create(gson, nonMatchingTypeToken);

    // Assert
    assertNull(adapter);
  }

  @Test
  void newFactory_toString_containsTypeAndAdapter() {
    // Arrange
    Class<String> type = String.class;
    TypeAdapter<String> typeAdapter = new TypeAdapter<String>() {
      @Override
      public String toString() {
        return "MyAdapter";
      }
      @Override
      public void write(com.google.gson.stream.JsonWriter out, String value) {}
      @Override
      public String read(com.google.gson.stream.JsonReader in) { return null; }
    };
    TypeAdapterFactory factory = TypeAdapters.newFactory(type, typeAdapter);

    // Act
    String toString = factory.toString();

    // Assert
    assertTrue(toString.contains(type.getName()));
    assertTrue(toString.contains("MyAdapter"));
  }
}
